```plantuml
@startuml

skinparam classAttributeIconSize 0

class Fruit {
  + show()
  + hide()
}

class SlidingFruit {
  + show()  // animate – slide in
}

class RollingFruit {
  + show()  // animate – roll in
}

class Banana #pink {
  + hide()  // animate – fade out
}

class Apple #pink {
  + hide()  // animate – fade out
}

class Orange {
  + hide()  // animate – slide out
}

SlidingFruit --|> Fruit
RollingFruit --|> Fruit
Banana --|> SlidingFruit
Apple --|> RollingFruit
Orange --|> RollingFruit

@enduml
```
